    93       * @param key The key that will be included in the record
    94       * @param value The record contents
    95       */
    96      public ProducerRecord(String topic, Integer partition, Long timestamp, K key, V value) {
    97          this(topic, partition, timestamp, key, value, null);
    98      }
    99
   100      /**
   101       * Creates a record to be sent to a specified topic and partition
   102       *
   103       * @param topic The topic the record will be appended to
   104       * @param partition The partition to which the record should be sent
